            Tags = """["customers","walkthrough"]""",
            ContentJson = """{"appRoute":"/customers","startButtonLabel":"Tour Customers","steps":[{"element":"[data-testid='new-customer-btn']","popover":{"title":"Add Customer Button","description":"Click here to create a new customer. You'll enter the customer name, optional company name, email, and phone. After saving, you'll be taken to the new customer's detail page.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Customers","description":"Search by customer name, company name, email, or phone number. Press Enter to apply the search. Results update in the table below.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Active/Inactive Filter","description":"Filter the list to show only Active customers, only Inactive customers, or All. New customers default to Active status.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Customers Table","description":"Shows all customers with columns for Name, Company, Email, Phone, Active status (green/gray chip), Contact count, Job count, and Created date. Click any row to navigate to the customer detail page. Click column headers to sort.","side":"top"}}]}"""
