            Summary = "Complete reference for every field, button, status, validation rule, tab, table column, and action in the Customers module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/customers"]""",
            Tags = """["customers","reference"]""",
            ContentJson = """{"title":"Customers Field Reference","groups":[{"heading":"Customer Create/Edit Form Fields","items":[{"label":"Name (required)","value":"Text input. The customer's display name. Must not be empty. Max 200 characters."},{"label":"Company Name","value":"Text input, optional. The customer's business or company name. Displayed below the customer name in the detail header."},{"label":"Email","value":"Text input, optional. Must be a valid email format when provided. Max 200 characters. Displayed as a clickable mailto: link in the detail header."},{"label":"Phone","value":"Text input with phone mask, optional. Formats as (XXX) XXX-XXXX. Displayed as a clickable tel: link in the detail header."},{"label":"Is Active (edit only)","value":"Toggle, shown only in detail-page inline Edit mode. Controls whether the customer appears in active-filtered views. Defaults to true for new customers."}]},{"heading":"Customer List Table Columns","items":[{"label":"Name","value":"Sortable. Customer display name."},{"label":"Company","value":"Sortable. Company name, or dash if not set."},{"label":"Email","value":"Sortable. Email address, or dash if not set."},{"label":"Phone","value":"Sortable. Phone number, or dash if not set."},{"label":"Active","value":"Sortable, filterable (enum). Green 'Active' chip or gray 'Inactive' chip."},{"label":"Contacts","value":"Sortable, center-aligned. Count of contacts linked to this customer."},{"label":"Jobs","value":"Sortable, center-aligned. Count of jobs linked to this customer."},{"label":"Created","value":"Sortable, date type. Customer creation date in MM/dd/yyyy format."}]},{"heading":"Stats Bar Metrics","items":[{"label":"Open Estimates","value":"Count of non-closed estimates for this customer. Clickable — switches to Estimates tab."},{"label":"Open Quotes","value":"Count of active quotes. Clickable — switches to Quotes tab."},{"label":"Open Orders","value":"Count of in-progress sales orders. Clickable — switches to Orders tab."},{"label":"Active Jobs","value":"Count of kanban jobs currently active. Clickable — switches to Jobs tab."},{"label":"Outstanding","value":"Total dollar amount of unpaid invoices, formatted as currency. Clickable — switches to Invoices tab."},{"label":"YTD Revenue","value":"Total revenue from this customer in the current year, formatted as currency. Not clickable."}]},{"heading":"Detail Page Tabs","items":[{"label":"Overview","value":"Account details, accounting integration info (provider, external ID, reference), and Credit Status card."},{"label":"Contacts","value":"Contact cards with avatar, name, role, email, phone, primary badge. Full CRUD (add, edit, delete)."},{"label":"Interactions","value":"Contact interaction log: calls, emails, meetings, notes. Filter by contact and type. Full CRUD."},{"label":"Addresses","value":"Address cards with type chip (Billing/Shipping/etc.), Default badge, and full address lines. Read-only display."},{"label":"Estimates","value":"Non-binding ballpark figures. DataTable with title, amount, status, valid-until, created. Create, edit, delete, convert to quote."},{"label":"Quotes","value":"Binding line-itemized quotes. DataTable with quote number, status, total, expiration date, created. Click to open quote detail dialog."},{"label":"Orders","value":"Sales orders. DataTable with order number, status, total, requested date, created. Click to open sales order detail dialog."},{"label":"Jobs","value":"Linked kanban jobs. DataTable with title, stage (color-coded chip), due date, created. Click to open job detail dialog."},{"label":"Invoices","value":"Issued invoices. DataTable with invoice number, status, total, due date, created. Click to open invoice detail dialog."},{"label":"Activity","value":"Chronological activity timeline of all changes, comments, and events. Uses shared ActivityTimeline component."}]},{"heading":"Contact Form Fields","items":[{"label":"First Name (required)","value":"Text input. Max 100 characters. Displayed in Last, First format throughout the app."},{"label":"Last Name (required)","value":"Text input. Max 100 characters."},{"label":"Email","value":"Text input, optional. Must be valid email format. Max 200 characters. Shown as clickable mailto: link on contact card."},{"label":"Phone","value":"Text input with phone mask, optional. Formats as (XXX) XXX-XXXX. Shown as clickable tel: link on contact card."},{"label":"Role","value":"Select dropdown, optional. Options loaded from reference data (contact_role group). '-- None --' is the null option."},{"label":"Primary Contact","value":"Toggle. When ON, marks this contact as the primary contact. Shown with a blue 'Primary' chip badge on the contact card."}]},{"heading":"Interaction Form Fields","items":[{"label":"Type (required)","value":"Select dropdown: Call, Email, Meeting, Note. Each type has a distinct icon in the table display."},{"label":"Contact","value":"Select dropdown, optional. Links the interaction to a specific contact. Options show all contacts for this customer plus '-- All Contacts --' null option."},{"label":"Subject (required)","value":"Text input. Max 200 characters. Brief description of the interaction."},{"label":"Date (required)","value":"Date picker. When the interaction occurred. Defaults to today."},{"label":"Duration (minutes)","value":"Number input, optional. Length of the interaction in minutes. Displayed formatted in the table."},{"label":"Notes","value":"Textarea, optional. 4 rows. Detailed notes about the interaction."}]},{"heading":"Interaction Table Columns","items":[{"label":"Type","value":"Sortable, filterable (enum). Chip with icon: phone (Call), email (Email), groups (Meeting), note (Note). Width 100px."},{"label":"Subject","value":"Sortable. The interaction subject text."},{"label":"Contact","value":"Sortable. Contact name (Last, First). Width 160px."},{"label":"Logged By","value":"Sortable. User who recorded the interaction. Width 160px."},{"label":"Date","value":"Sortable, date type. Interaction date in MM/dd/yyyy format. Width 120px."},{"label":"Duration","value":"Sortable, number type. Duration in minutes, formatted. Width 90px."},{"label":"Actions","value":"Edit and delete icon buttons. Width 80px."}]},{"heading":"Estimate Form Fields","items":[{"label":"Title (required)","value":"Text input. Max 300 characters. Brief title for the estimate."},{"label":"Description","value":"Textarea, optional. 2 rows. More detailed description of the estimate scope."},{"label":"Estimated Amount (required)","value":"Currency input with $ prefix. Must be >= 0."},{"label":"Valid Until","value":"Date picker, optional. Expiration date for the estimate."},{"label":"Status (edit only)","value":"Select dropdown, shown only when editing. Options: Draft, Sent, Accepted, Declined, Expired."},{"label":"Notes","value":"Textarea, optional. 2 rows. Internal notes."}]},{"heading":"Estimate Table Columns","items":[{"label":"Title","value":"Sortable. Estimate title text."},{"label":"Amount","value":"Sortable, number type, right-aligned. Estimated amount formatted as currency. Width 120px."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip: Draft, Sent, Accepted, Declined, Expired. Width 110px."},{"label":"Valid Until","value":"Sortable, date type. Expiration date in MM/dd/yyyy format. Width 110px."},{"label":"Created","value":"Sortable, date type. Creation date in MM/dd/yyyy format. Width 100px."},{"label":"Actions","value":"Convert to Quote button (forward icon, hidden if already converted) and Delete button. Width 100px."}]},{"heading":"Credit Status Card Fields","items":[{"label":"Risk Level","value":"Chip badge: Low (green), Medium (yellow), High (red), OnHold (red). Calculated from credit utilization and hold status."},{"label":"Credit Hold Banner","value":"Red banner shown when customer is on hold. Displays hold reason and a Release button."},{"label":"Credit Limit","value":"Currency value or 'None' if no limit set. The maximum credit exposure allowed."},{"label":"Open AR","value":"Currency value. Total of unpaid invoices (accounts receivable)."},{"label":"Pending Orders","value":"Currency value. Total of in-progress sales orders not yet invoiced."},{"label":"Total Exposure","value":"Currency value. Open AR + Pending Orders combined. Turns red when over limit."},{"label":"Available Credit","value":"Currency value. Credit Limit minus Total Exposure. Turns red when negative. Only shown when credit limit is set."},{"label":"Utilization","value":"Percentage. Total Exposure / Credit Limit × 100. Only shown when credit limit is set."},{"label":"Utilization Bar","value":"Visual progress bar. Turns red when utilization exceeds 100%."},{"label":"Place Hold Button","value":"Opens dialog to place credit hold with required reason (textarea, max 500 chars). Blocks new orders for this customer."},{"label":"Release Button","value":"Shown on hold banner. Removes the credit hold and unblocks new orders."}]},{"heading":"Address Card Fields","items":[{"label":"Type","value":"Chip badge showing address type: Billing, Shipping, or other configured types."},{"label":"Default","value":"Blue 'Default' chip badge shown on the default address."},{"label":"Line 1","value":"Primary street address line."},{"label":"Line 2","value":"Secondary address line (suite, unit, etc.). Only shown if set."},{"label":"City, State ZIP","value":"City name, 2-letter state code, and ZIP code on one line."},{"label":"Country","value":"Country name."}]},{"heading":"Quotes Tab Table Columns","items":[{"label":"Quote #","value":"Sortable. The quote reference number."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip: Draft, Sent, Accepted, Declined, Expired."},{"label":"Total","value":"Sortable, number type. Quote total formatted as currency."},{"label":"Expiration Date","value":"Sortable, date type. When the quote expires. MM/dd/yyyy format."},{"label":"Created","value":"Sortable, date type. Creation date. MM/dd/yyyy format."}]},{"heading":"Orders Tab Table Columns","items":[{"label":"Order #","value":"Sortable. The sales order reference number."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded status chip."},{"label":"Total","value":"Sortable, number type. Order total formatted as currency."},{"label":"Requested Date","value":"Sortable, date type. Customer's requested delivery date. MM/dd/yyyy format."},{"label":"Created","value":"Sortable, date type. Order creation date. MM/dd/yyyy format."}]},{"heading":"Jobs Tab Table Columns","items":[{"label":"Title","value":"Sortable. The job title."},{"label":"Stage","value":"Sortable. Color-coded chip matching the kanban board stage color via --chip-color custom property."},{"label":"Due Date","value":"Sortable, date type. Job due date. MM/dd/yyyy format."},{"label":"Created","value":"Sortable, date type. Job creation date. MM/dd/yyyy format."}]},{"heading":"Invoices Tab Table Columns","items":[{"label":"Invoice #","value":"Sortable. The invoice reference number."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded status chip."},{"label":"Total","value":"Sortable, number type. Invoice total formatted as currency."},{"label":"Due Date","value":"Sortable, date type. Payment due date. MM/dd/yyyy format."},{"label":"Created","value":"Sortable, date type. Invoice creation date. MM/dd/yyyy format."}]},{"heading":"Buttons and Actions","items":[{"label":"Add Customer (list page)","value":"Primary button. Opens quick-create dialog with Name, Company, Email, Phone. data-testid: new-customer-btn"},{"label":"Save (create dialog)","value":"Creates the customer. Disabled when form is invalid or save is in progress. Shows validation popover on hover. data-testid: customer-save-btn. After save, navigates to the new customer's detail page."},{"label":"Edit (detail page)","value":"Toggles the header into inline Edit mode (no dialog). The Overview tab's identity fields become editable in place with inline Save/Cancel; the button switches to a Cancel/Done affordance. Includes the Is Active toggle not available in create."},{"label":"Archive (detail page)","value":"Archive icon button. Opens confirmation dialog with severity 'warn'. Archives (soft-deletes) the customer and navigates back to the list."},{"label":"Back to Customers","value":"Chevron-left link in the detail header. Navigates to /customers."},{"label":"Add Contact","value":"Primary button on Contacts tab. Opens contact create dialog."},{"label":"Edit Contact","value":"Edit icon button on each contact card. Opens pre-filled contact edit dialog."},{"label":"Remove Contact","value":"Delete icon button (danger style) on each contact card. Confirmation dialog required."},{"label":"Log Interaction","value":"Primary button on Interactions tab. Opens interaction create dialog."},{"label":"Edit Interaction","value":"Edit icon button in interactions table row. Opens pre-filled edit dialog."},{"label":"Delete Interaction","value":"Delete icon button (danger style) in interactions table row. Confirmation dialog required."},{"label":"New Estimate","value":"Primary button on Estimates tab. Opens estimate create dialog."},{"label":"Convert to Quote (estimate)","value":"Forward icon button on estimate row. Converts the estimate to a formal quote. Hidden if already converted."},{"label":"Delete Estimate","value":"Delete icon button (danger style) on estimate row. Confirmation dialog required."},{"label":"Place Hold","value":"Small button on Credit Status card. Opens hold reason dialog."},{"label":"Release Hold","value":"Small button on credit hold banner. Immediately releases the hold."}]},{"heading":"Validation Rules","items":[{"label":"Customer Name","value":"Required. Max 200 characters. Cannot be empty."},{"label":"Customer Email","value":"Optional. Must be valid email format when provided. Max 200 characters."},{"label":"Contact First Name","value":"Required. Max 100 characters."},{"label":"Contact Last Name","value":"Required. Max 100 characters."},{"label":"Contact Email","value":"Optional. Must be valid email format. Max 200 characters."},{"label":"Interaction Type","value":"Required. Must select one of: Call, Email, Meeting, Note."},{"label":"Interaction Subject","value":"Required. Max 200 characters."},{"label":"Interaction Date","value":"Required. Must select a date."},{"label":"Estimate Title","value":"Required. Max 300 characters."},{"label":"Estimated Amount","value":"Required. Must be a number >= 0."},{"label":"Credit Hold Reason","value":"Required when placing a hold. Max 500 characters."},{"label":"Submit button popover","value":"When form is invalid, hovering over Save shows a validation popover listing which fields need attention."}]}]}"""
