        {
            Title = "Customers Knowledge Check",
            Slug = "customers-quiz",
            Summary = "Test your knowledge of the Customers module: detail tabs, contacts, credit management, estimates, interactions, and the quote-to-cash flow.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/customers"]""",
            Tags = """["customers","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"cu1","text":"A new customer calls to request a quote. What is the first step in QB Engineer?","options":[{"id":"a","text":"Create a Quote directly from the Quotes page"},{"id":"b","text":"Navigate to Customers, click Add Customer, fill in their details, then create an estimate or quote from their detail page","isCorrect":true},{"id":"c","text":"Create a Job on the Kanban Board and assign the customer later"},{"id":"d","text":"Add them to the Leads module and wait for conversion"}],"explanation":"Start by creating the customer record. From their detail page, you can create estimates or quotes directly in the Estimates or Quotes tabs. This ensures all activity is linked to the customer."},{"id":"cu2","text":"You're on a customer's detail page and want to quickly see how many active jobs they have. Where do you look?","options":[{"id":"a","text":"Click the Jobs tab and count the rows in the table"},{"id":"b","text":"Check the stats bar — the 'Active Jobs' metric shows the count, and clicking it jumps to the Jobs tab","isCorrect":true},{"id":"c","text":"Run a report filtered by customer name"},{"id":"d","text":"Go to the Kanban Board and filter by customer"}],"explanation":"The stats bar below the customer header shows live aggregates including Active Jobs. Each stat is clickable — clicking 'Active Jobs' switches directly to the Jobs tab for details."},{"id":"cu3","text":"A customer's credit status shows 'Total Exposure' in red. What does this indicate?","options":[{"id":"a","text":"The customer has been on hold for more than 30 days"},{"id":"b","text":"The customer's combined open AR balance plus pending orders exceeds their credit limit","isCorrect":true},{"id":"c","text":"The customer has overdue invoices past 90 days"},{"id":"d","text":"The customer's account has been flagged for review"}],"explanation":"Total Exposure = Open AR + Pending Orders. When this exceeds the credit limit, the value displays in red to alert you that the customer is over their allowed credit."},{"id":"cu4","text":"You need to block a customer from placing new orders due to unpaid invoices. How do you do this?","options":[{"id":"a","text":"Set the customer's status to Inactive via inline Edit mode"},{"id":"b","text":"Delete all their open sales orders"},{"id":"c","text":"On the Overview tab, click 'Place Hold' on the Credit Status card and enter a reason","isCorrect":true},{"id":"d","text":"Contact your admin to disable their account"}],"explanation":"The Credit Status card on the Overview tab has a 'Place Hold' button. Clicking it opens a dialog where you must enter a reason. Once on hold, new orders are blocked until the hold is released."},{"id":"cu5","text":"A customer contact has been promoted and their role has changed. Where do you update this?","options":[{"id":"a","text":"Go to Admin → Reference Data and update their role entry"},{"id":"b","text":"Navigate to the customer's Contacts tab, click the edit icon on their contact card, and change the Role dropdown","isCorrect":true},{"id":"c","text":"Edit the contact directly from the customer list page"},{"id":"d","text":"The role field is read-only and cannot be changed after creation"}],"explanation":"On the Contacts tab, each contact card has an edit icon button. Click it to open the edit dialog where you can change any field including the Role dropdown. Role options come from reference data."},{"id":"cu6","text":"You had a phone call with a customer about an upcoming project. Where do you log this?","options":[{"id":"a","text":"Add a note to the Activity tab"},{"id":"b","text":"Create a new estimate on the Estimates tab"},{"id":"c","text":"Go to the Interactions tab, click 'Log Interaction', select Type: Call, fill in the subject, date, duration, and notes","isCorrect":true},{"id":"d","text":"Send an email from the Contacts tab"}],"explanation":"The Interactions tab is designed for tracking customer communications. Click 'Log Interaction', select Call as the type, and fill in the details including subject, date, duration, and any notes from the conversation."},{"id":"cu7","text":"An estimate has been accepted by the customer. What is the next step in the quote-to-cash flow?","options":[{"id":"a","text":"Create a job directly from the estimate"},{"id":"b","text":"Click the Convert to Quote button on the estimate row to create a formal, line-itemized quote","isCorrect":true},{"id":"c","text":"Change the estimate status to 'Converted' manually"},{"id":"d","text":"Delete the estimate and create a sales order instead"}],"explanation":"Estimates are non-binding ballpark figures. Once accepted, use the Convert to Quote button (forward icon) to create a formal, line-itemized quote. The quote can then be converted to a sales order. The convert button is hidden if the estimate has already been converted."},{"id":"cu8","text":"How is the customer detail page's tab set determined, and which tab shows the Credit Status card?","options":[{"id":"a","text":"There are always exactly 10 fixed tabs; the Credit Status card is on the Invoices tab"},{"id":"b","text":"The tab set is lifecycle-driven and varies (Active, Prospect, or Archived); the Credit Status card is on the Overview tab","isCorrect":true},{"id":"c","text":"There is a fixed Credit tab that always appears; it shows the Credit Status card"},{"id":"d","text":"The tabs are the same for every customer; the Credit Status card is on a dedicated Financials tab"}],"explanation":"The tab set is not fixed — it is resolved from the customer's lifecycle bucket. Overview is always first and Activity always last; the middle tabs vary: Active customers see Contacts, Addresses, Estimates, Quotes, Orders, Jobs, Invoices, Pricing, and Interactions (11 tabs total); Prospects see a shorter sales-intake set (7); Archived customers see a read-only history set (6). The Credit Status card always lives on the Overview tab."},{"id":"cu9","text":"You want to find all inactive customers who were created in the last year. How do you filter the customer list?","options":[{"id":"a","text":"Set the Active filter to 'Inactive' — the table supports date column sorting to find recent entries","isCorrect":true},{"id":"b","text":"Run a search for 'inactive' in the search box"},{"id":"c","text":"Go to Reports and create a custom customer report"},{"id":"d","text":"You cannot filter inactive customers — they are hidden by default"}],"explanation":"The customer list page has an Active/Inactive filter dropdown. Set it to 'Inactive' to show only inactive customers, then sort by the Created column (date type) to find the most recent ones."},{"id":"cu10","text":"What information is displayed on a contact card in the Contacts tab?","options":[{"id":"a","text":"Just the contact's name and email"},{"id":"b","text":"Avatar with initials, name (Last, First format), role, email (mailto link), phone (tel link), and Primary badge if applicable","isCorrect":true},{"id":"c","text":"Name, job title, department, and office location"},{"id":"d","text":"Name, email, and a list of their recent interactions"}],"explanation":"Contact cards show an avatar (with initials), the name in Last, First format, their role (from reference data), clickable email and phone links, and a blue 'Primary' chip badge if they are the primary contact."},{"id":"cu11","text":"A customer's credit utilization bar is red and shows 115%. What actions can you take?","options":[{"id":"a","text":"Nothing — the system automatically blocks orders when over limit"},{"id":"b","text":"Place a credit hold via the Place Hold button, or increase the credit limit via the accounting system, or collect on outstanding invoices to reduce AR","isCorrect":true},{"id":"c","text":"Delete the oldest unpaid invoices to bring the balance down"},{"id":"d","text":"Archive the customer to prevent further orders"}],"explanation":"When over the credit limit, you can place a credit hold to formally block new orders (with a required reason), work with accounting to increase the credit limit, or focus on collecting outstanding invoices to reduce the AR balance and bring utilization back under 100%."},{"id":"cu12","text":"You want to share a direct link to a customer's Orders tab with a colleague. What URL format would you share?","options":[{"id":"a","text":"/customers?tab=orders&id=42"},{"id":"b","text":"/customers/42/orders","isCorrect":true},{"id":"c","text":"/customers/42?detail=orders"},{"id":"d","text":"/orders?customer=42"}],"explanation":"Customer detail pages use the URL pattern /customers/:id/:tab. Each tab is a route segment, so the Orders tab for customer 42 would be /customers/42/orders. This URL is bookmarkable and shareable."},{"id":"cu13","text":"What is the difference between an Estimate and a Quote in the customer detail?","options":[{"id":"a","text":"They are the same thing with different names"},{"id":"b","text":"Estimates are non-binding ballpark figures with a single amount; Quotes are binding, line-itemized commitments with per-item pricing","isCorrect":true},{"id":"c","text":"Estimates are for new customers; Quotes are for existing customers"},{"id":"d","text":"Estimates require approval; Quotes do not"}],"explanation":"Estimates are non-binding ballpark figures with a single estimated amount — quick and informal. Quotes are formal, binding commitments with individual line items (part, quantity, unit price). Estimates can be converted to Quotes when the customer is ready for a firm price."},{"id":"cu14","text":"You're filtering the Interactions tab and want to see only meetings with a specific contact. How?","options":[{"id":"a","text":"Type 'meeting' in the search box"},{"id":"b","text":"Set the Contact filter to the specific contact and the Type filter to 'Meeting'","isCorrect":true},{"id":"c","text":"Sort the table by Type column and scroll to Meeting rows"},{"id":"d","text":"Interactions cannot be filtered by both contact and type simultaneously"}],"explanation":"The Interactions tab toolbar has two filter dropdowns: Contact (to filter by specific contact or '-- All Contacts --') and Type (to filter by Call, Email, Meeting, Note, or '-- All Types --'). Both filters can be used simultaneously."},{"id":"cu15","text":"When you archive a customer, what happens to their data?","options":[{"id":"a","text":"All data is permanently deleted including contacts, orders, and invoices"},{"id":"b","text":"The customer record is soft-deleted — all history is preserved but the customer won't appear in active views","isCorrect":true},{"id":"c","text":"Only the customer name is kept; all related records are purged"},{"id":"d","text":"The customer is moved to a separate Archive database"}],"explanation":"Archiving uses soft delete (sets DeletedAt timestamp). All data is preserved — contacts, orders, jobs, invoices, activity history — nothing is lost. The customer simply won't appear in standard filtered views. This follows the app-wide rule of never hard-deleting records."}]}"""
