            ContentJson = """{"title":"Customer Pricing Field Reference","groups":[{"heading":"Where to Find It","items":[{"label":"Pricing tab","value":"On the customer detail page for Active customers only. Route: /customers/:id/pricing. Hidden for Prospect and Archived customers."},{"label":"Who uses it","value":"Office Managers (and Admin/Manager) adjust customer-specific price lists in context."}]},{"heading":"Price List Form Fields","items":[{"label":"Name (required)","value":"Text input, max 100 chars. Identifies the price list (e.g., '2026 Contract Pricing')."},{"label":"Description","value":"Textarea, 2 rows, optional. Free-form notes about the list."},{"label":"Effective From","value":"Date picker, optional. Start of the date window the list applies to."},{"label":"Effective To","value":"Date picker, optional. End of the window. Header shows 'Always' when both dates are blank, 'From X' / 'Until Y' when only one is set."},{"label":"Default","value":"Toggle. Marks this as the customer's default price list — auto-selected when the tab opens."},{"label":"Active","value":"Toggle. Inactive lists are retained but not applied."}]},{"heading":"Price List Entry Form Fields","items":[{"label":"Part","value":"Typeahead entity picker (search by part number/name). Required. You can create a new part inline. Locked when editing an existing entry."},{"label":"Unit Price (required)","value":"Currency input. The negotiated price per unit at this quantity break."},{"label":"Min Quantity (required)","value":"Number input. The quantity threshold this price applies at. The highest Min Quantity still <= the ordered quantity wins."},{"label":"Currency (required)","value":"Select dropdown. The currency for this entry's price."},{"label":"Notes","value":"Textarea, 3 rows, optional. Context for the entry."}]},{"heading":"Inline Cell Editing","items":[{"label":"Editable cells","value":"Min Quantity and Unit Price columns. Click the cell to edit in place."},{"label":"Commit / cancel","value":"Enter commits; Escape cancels. A spinner shows while saving; an error marker (!) with tooltip appears on invalid values."},{"label":"Row actions","value":"Edit (pencil) opens the full entry dialog; Delete (trash) removes the entry after confirmation."}]},{"heading":"CSV Bulk Import","items":[{"label":"Import button","value":"Upload-file button in the entries header. Opens the two-step import dialog for the selected list."},{"label":"Download Template","value":"Link in the file-picker step that downloads a CSV with the correct column layout."},{"label":"Preview summary","value":"After parsing, shows counts of rows to Add, Update, and rows in Error. Each preview row is tagged with its action and any error message."},{"label":"Apply","value":"Disabled while any row is in error. Applies the import; matching is by part + minimum quantity so re-imports update rather than duplicate."},{"label":"Back / Cancel","value":"Back returns to the file picker from preview; Cancel closes the dialog."}]},{"heading":"List Management","items":[{"label":"+ New List","value":"Creates a price list. Empty state shows 'Create First List' when none exist."},{"label":"List selector","value":"Dropdown appears in the header only when the customer has more than one list."},{"label":"Edit / Delete list","value":"Pencil and trash icons in the entries header. Deleting a list with entries warns about the entry count first."}]},{"heading":"Downstream Use","items":[{"label":"Order/Quote line auto-fill","value":"Selecting a part on a Sales Order or Quote line for this customer auto-fills the unit price from the applicable price-list entry for the ordered quantity."}]}]}"""
